.whatsapp-desktop{display:inline-block}
.whatsapp-mobile{display:none}
.top-bar{display:none;height:40px;background:$(top.menu.color);box-shadow:inset 0 -15px 30px rgb(0 0 0 / 40%), 0 2px 10px rgb(0 0 0 / 50%);}
#top-menu{float:left}
#top-menu .selectnav, .jobiki-Mmenu-logo{display:none}
.menu-top li{display:inline-block;line-height:40px;padding:0}
.menu-top li a{color:$(top.color);text-transform:capitalize;font-size:12px;text-decoration:none}
.menu-top li a:after{content:"-";margin:0 5px;color:$(top.color)}
.menu-top li:last-child a:after{content:" ";display:none}
.menu-top li a .fa{margin-right:5px}
.menu-top li a:hover{opacity:0.9}
#top-social{float:right}
.dark .title h3, .dark .follow-by-email-title, .dark .post-snip .post-author,.dark .author-description span, .dark .list-label li a:before{color:#fff}
.dark .job-relateds .related-item,.dark .blog-pager .page-active ,.dark .blog-pager a ,.dark.blog-pager span {background:#222}
.dark .FollowByEmail .widget-content,  .dark .piki-ads-res, .dark .job-related .widget-title, .dark .comments .comment .comment-actions a, .dark .piki-ads ,.dark .main-title, .dark .darkmode-box .widget>.widget-title, .dark .job-related .widget-title.dark .cloud-label li a  ,.dark .title-wrap, .dark .blog-pager, .dark .comments .comments-content .comment-content, .dark .queryMessage{background:#1c1c26}
.dark .entry-title, .dark h3.title, .dark .queryMessage{color:#E4E4E4! important}
.dark .content article{background:transparent}
.dark .post-body ol>li:before{color:#eee}
.dark .job-hero-wrap, .dark .job-hero, .dark #jobikisMenu-pro ul>li>ul{background: #0a091b;}
.dark .top-bar{background: #0a091b;border:none}
.mega-mode{ display: none !important;position:relative;padding: 0 15px; margin-right:10px;text-align:center;border-radius: 30px;display:inline-block;align-items:center;z-index:999}
.dark-button{display:none;}
.dark-button + .dark-toggle{outline:0;display:inline-block;width:40px;height:20px;vertical-align: middle;position:relative;cursor:pointer;margin-left:5px;-webkit-user-select:none;-moz-user-select:none;-ms-user-select:none;user-select:none;}
.dark-mode + .dark-toggle{border-radius:99em;transition:all .4s ease}
.dark-mode + .dark-toggle:after{content:'\f186';font-family:'Font Awesome 5 Free';font-weight:900;color:#fff;line-height: 18px;border-radius:100px;background:#887fff;transition:left 0.3s cubic-bezier(0.175,0.885,0.32,1.275),padding 0.3s ease,margin 0.3s ease;position:absolute;width:18px;height:18px;top:1px;left:2px;box-shadow:0 3px 6px rgba(0,0,0,0.16),0 3px 6px rgba(0,0,0,0.23)}
.dark .dark-mode + .dark-toggle{background:#FFEDC6}
.dark-mode + .dark-toggle{background:#6f6f6f}
.dark .dark-mode + .dark-toggle:after{left:53%;background:#ff9f43}
.dark .read-more{background:#211b44}
.social-sec .social li{display:inline-block;list-style:none;line-height:40px}
.social-sec .social li a{display:block;height:40px;width:25px;line-height:40px;font-size:15px;text-align:center;color:$(top.color)}
.social-sec .social{width:100%;text-align:right;line-height:40px}
.jobiki-page{bottom:0;text-align:center;width:100%;border-top:1px solid #737373;margin:5px 0}
.jobiki-page .nav1 li{display:inline-block;padding:0;margin:0}
.jobiki-page ul.nav1{text-align:center;display:inline-block}
.jobiki-page .nav1 li a{font-size:14px;font-weight:400;display:block;color:#dadada;padding:0 0 0 5px;margin:0 0 0 10px}
.dark .entry-title, .dark h3.title, .dark .queryMessage{color:#E4E4E4! important}
#jobikis-list>.mega-menu{position:unset!important}
.jobikisMenu-pro li:hover .job-cont-creative{opacity:1;visibility:visible}
.drop-down>a:after{content:'\f078';float:right;font-family:'Font Awesome 5 Free';font-size:9px;font-weight:900;margin:-1px 0 0 5px}
.job-cont-creative{top:59px;transition:all .3s ease;-webkit-transition:all .3s ease;-moz-transition:all .3s ease;-o-transition:all .3s ease;opacity:0;visibility:hidden;width:100%;left:0;box-sizing:border-box;right:0;z-index:3333;color:var(--white-bg);height:auto;padding:20px;text-align:center;min-height:100px;position:absolute;background-color:#ffffff;box-shadow:0 10px 10px rgba(0,0,0,0.28)}
.jobikisMenu-pro li:hover .job-cont-creative{margin-top:1px;opacity:1;visibility:visible}
.job-mposts-mg{width:24%;box-sizing:border-box;float:left;overflow:hidden;position:relative}
.job-mposts-mg:last-child{margin-right:0}
.job-mposts-mg .post-filter-link{height:100%}
.job-mposts-mgs{display:flex;justify-content:space-between;flex-wrap:wrap}
.job-mposts-mgs .job-mposts-mthumb{height:191px;display:block;overflow:hidden;}
.job-mposts-mgs .entry-title{font-size:14px;font-weight:700;line-height:1.5em}
/*----- Table of Content (TOC). -----*/
.tociki-pro{display:flex;width:100%;clear:both;margin:0}
.tociki-inner{position:relative;max-width:100%;font-size:14px;color:#000;background-color:rgba(165 165 165 / 10%);overflow:hidden;line-height:23px;border:1px solid #a0a0a0;border-radius:5px}
a.tociki-title{position:relative;display:flex;align-items:center;justify-content:space-between;height:38px;font-size:16px;font-weight:600;color:#000;padding:0 15px;margin:0}
.tociki-title-text{display:flex}
.tociki-title-text:before{content:'\f0cb';font-family:'Font Awesome 5 Free';font-size:14px;font-weight:900;margin:0 5px 0 0}
.tociki-title:after{content:'\f078';font-family:'Font Awesome 5 Free';font-size:12px;font-weight:900;margin:0 0 0 25px}
.tociki-title.opened:after{content:'\f077'}
a.tociki-title:hover{text-decoration:none}
#tociki{display:none;padding:0 15px 10px;margin:0}
#tociki ol{padding:0 0 0 15px}
#tociki li{font-size:14px;margin:10px 0}
#tociki li a{color:$(main.color)}
#tociki li a:hover{color:$(main.hover);text-decoration:underline}
/*----- Cap the total number of ads (widgets and inline ads). -----*/
#top-ad-placeholder .widget > .widget-title, #bottom-ad-placeholder .widget > .widget-title{display:none}
#top-ad-placeholder, #bottom-ad-placeholder {margin: 15px 0; padding: 0; width: 100%; overflow: hidden;}
.main-ads-pikihome{position:relative;float:left;width:100%;margin:15px 0 0}
.main-ads-pikihome .widget{position:relative;float:left;width:100%;line-height:0;margin:0 0 5px}
.main-ads-pikihome .widget > .widget-title, #post-placeholder .widget > .widget-title{display:none}
 #post-placeholder{position:relative;box-sizing: border-box;width:100%; height:auto;padding: 0 5px;margin:10px 0}
 #post-placeholder .widget{position:relative;width:100%;line-height:0; height:auto}

/*----- Standard footer section under Parent of Center Container element. -----*/
#footer-container{display:block;width:100%;color:$(footer.pages.color);margin:auto;padding:0;border-top: 1px solid rgba(255, 255, 255, 0.08);overflow:hidden}
#footer-container .footer-copyright{position:relative;float:none;text-align: center;font-size:13px;line-height:40px;margin:0}
.copyright-text{margin:0}
#footer-container .footer-copyright a{color:$(footer.widget.title.color)}
#footer-container .footer-copyright a:hover{color:$(footer.pages.color)}
#footer-haburger-menu{float:none;position:relative;display:block;margin:5px 0 0;text-align:center}
#footer-haburger-menu .widget>.widget-title,#footer-copyright .widget>.widget-title{display:none}
.footer-haburger-menu ul li{position:relative;margin:0;float:none;display:inline-block;text-align:center}
.footer-haburger-menu ul li a{display:block;overflow:hidden;font-size:14px;font-weight:600;color:$(footer.pages.color);height:30px;line-height:30px;padding:0 5px;margin:0 10px 0;border-radius:3px;border:1px solid rgb(0 0 0 / 7%);box-shadow:0 2px 8px rgb(0 0 0 / 12%);background:rgb(0 0 0 / 10%)}
#footer-haburger-menu ul li a:hover{color:$(footer.pages.hover.color)}

/*-- Top Social Menu CSS (IE/ IE9 etc.) --*/
.socialFilter .external-link a{background-color:$(main.hover)}
.sharing-button .facebook a,.sharing-button .facebook-f a{background-color:#3b5999}
.sharing-button .twitter a,.sharing-button .twitter-square a{background-color:#00acee}
.sharing-button .reddit a{background-color:#ff4500}
.sharing-button .pinterest a,.sharing-button .pinterest-p a{background-color:#ca2127}
.sharing-button .linkedin a{background-color:#0077b5}
.sharing-button .whatsapp a{background-color:#3fbb50}
.sharing-button .email a{background-color:#888}

/*-- Top Social Menu Code (jQuery Latest Menu) --*/
#jobikis-sticky{position:relative;float:left;width:100%;height:auto;margin:0}
.job-hero-wrap,.job-hero{position:relative;float:left;width:100%;height:56px;background:$(main.menu);box-sizing:border-box;padding:0;margin:0 0 5px;box-shadow: 5px 5px 8px 0px rgba(224 223 223 / 48%);}
#jobikis-sticky .container{position:relative;margin:0 auto}
.jobikisLogo-wrap{position:relative;width: 100%;float:left;margin:0 30px 0 0}
.jobikisLogo{position:relative;float:left;height:44px;padding:5px 0;margin:0}
.jobikisLogo .jobikisLogo-img{display: flex; align-items: center; height: 40px; overflow: hidden; margin: 0;}
.jobikisLogo img{display: block; max-width: 100%; max-height: 100%; margin: 0;}
.show-jobiki-Mmenu-p{display: none; color:#000; height: 40px; font-size: 17px; padding: 0 15px; }
.header-section {position: relative; display: flex; flex-wrap: wrap; justify-content: space-between; float: left; width: 100%; margin: 0; }
.header-left{position: static; display: flex; margin: 0; }
.header-right{position: absolute; top: 0; right: 0; margin: 0; }
.jobikisLogo .widget{position: relative; display: flex; align-items: center; height: 100%; margin: 0; }
.jobikisLogo-img .logo-img{display: flex; align-items: center; height: 40px; overflow: hidden; margin: 0; }
.jobikisLogo h1{display:block;font-size:25px;color:$(navbar.color);height:30px;line-height:30px;overflow: hidden;padding:0;margin:0}
.jobikisLogo h1 a{color:$(navbar.color)}
.jobikisLogo #title-header{display:none;visibility:hidden}
.main-menu-wrap{position:static;height:56px;margin:0}
#jobikisMenu-pro .widget,#jobikisMenu-pro .widget>.widget-title{display:none}
#jobikisMenu-pro .show-menu{display:block}
#jobikisMenu-pro{position:static;height:56px;z-index:10}
#jobikisMenu-pro ul>li{position:relative;float:left;display:inline-block;padding:0;margin:0}
#jobikis-list>li>a{position:relative;display:block;height:56px;font-size:14px;color:$(submenu.color);font-weight:600;text-transform:capitalize;line-height:56px;padding:0 10px;margin:0}
#jobikis-list>li>a:hover{background:$(widget.background);color:$(widget.title.color)}
#jobikisMenu-pro ul>li>ul{position:absolute;float:left;left:0;top:59px;width:180px;background:$(submenu.background.color);z-index:99999;visibility:hidden;opacity:0;-webkit-transform:translateY(-10px);transform:translateY(-10px);padding:0;box-shadow:0 2px 5px 0 rgba(0,0,0,0.15),0 2px 10px 0 rgba(0,0,0,0.17)}
#jobikisMenu-pro ul>li>ul>li>ul{position:absolute;top:0;left:100%;-webkit-transform:translateX(-10px);transform:translateX(-10px);margin:0}
#jobikisMenu-pro ul>li>ul>li{display:block;float:none;position:relative}
#jobikisMenu-pro ul>li>ul>li a{position:relative;display:block;height:36px;font-size:13px;color:$(widget.title.color);line-height:36px;font-weight:400;box-sizing:border-box;padding:0 15px;margin:0;border-bottom:1px solid rgba(155,155,155,0.07)}
#jobikisMenu-pro ul>li>ul>li:last-child a{border:0}
#jobikisMenu-pro ul>li>ul>li:hover>a{color:#ccc}
#jobikisMenu-pro ul>li.sub-tab>a:after{content:'\f078';float:right;font-family:'Font Awesome 5 Free';font-size:9px;font-weight:900;margin:-1px 0 0 5px}
#jobikisMenu-pro ul>li>ul>li.sub-tab>a:after{content:'\f054';float:right;margin:0}
#jobikisMenu-pro ul>li:hover>ul,#jobikisMenu-pro ul>li>ul>li:hover>ul{visibility:visible;opacity:1;-webkit-backface-visibility:hidden;backface-visibility:hidden;-webkit-transform:translate(0);transform:translate(0)}
#jobikisMenu-pro ul ul{transition:all .35s ease}
.loading-icon{width:100%;height:100%;line-height: 300px;display:block;text-align:center}
.breaking-job-news .loading-icon{line-height: 38px;}
.breaking-job-news .widget .breaking-new-news .widget-content span.error-status{padding:0;line-height: 30px;}
.breaking-job-news .loading-icon:after{width:20px;height:20px;}
.loading-icon:after{content:"";width:40px;height:40px;border-radius: 50%;border:2px solid $(main.color);border-right: 2px solid #c1c1c1;display: inline-block;
animation: runload 0.6s infinite
}
@-webkit-keyframes runload {
0%{-webkit-transform:rotate(0deg);transform:rotate(0deg)}
to{-webkit-transform:rotate(1turn);transform:rotate(1turn)}
}
@keyframes runload {
0%{-webkit-transform:rotate(0deg);transform:rotate(0deg)}
to{-webkit-transform:rotate(1turn);transform:rotate(1turn)}
}
.loading-frame{-webkit-animation-duration:.5s;animation-duration:.5s;-webkit-animation-fill-mode:both;animation-fill-mode:both}
@keyframes fadeIn {
from{opacity:0}
to{opacity:1}
}
.run-time{animation-name:fadeIn}
@keyframes fadeInUp {
from{opacity:0;transform:translate3d(0,5px,0)}
to{opacity:1;transform:translate3d(0,0,0)}
}
.load-time{animation-name:fadeInUp}
.overlay{visibility:hidden;opacity:0;position:fixed;top:0;left:0;right:0;bottom:0;z-index:1000;margin:0;transition:all .25s ease}
.show-jobiki-Mmenu-p:before{content:"\f0c9";font-family:'Font Awesome 5 Free';font-size:20px;font-weight:900}
#jobiki-Mmenu-p{display:none;position:fixed;width:100%;height:100%;top:0;left:0;bottom:0;background:$(menu.color);background:-moz-linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);background:-webkit-linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);background:linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);overflow:auto;z-index:1010;left:0;-webkit-transform:translateX(-100%);transform:translateX(-100%);visibility:hidden;box-shadow:3px 0 7px rgba(0,0,0,0.1);-webkit-transition:all .5s cubic-bezier(.79,.14,.15,.86);-moz-transition:all .5s cubic-bezier(.79,.14,.15,.86);-o-transition:all .5s cubic-bezier(.79,.14,.15,.86);transition:all .5s cubic-bezier(.79,.14,.15,.86)}
.jobikis-open #jobiki-Mmenu-p{-webkit-transform:translateX(0);transform:translateX(0);visibility:visible;opacity:.99;-webkit-transition:all .5s cubic-bezier(.79,.14,.15,.86);-moz-transition:all .5s cubic-bezier(.79,.14,.15,.86);-o-transition:all .5s cubic-bezier(.79,.14,.15,.86);transition:all .5s cubic-bezier(.79,.14,.15,.86)}
.jobikis-wrap{float:left;width:100%;margin:30px 0;opacity:0;transition:all ease-in-out .3s;box-sizing:border-box;box-shadow:0 0 20px rgba(0,0,0,0.15)}
#jobiki-Mmenu-p{transition:all .6s ease-in-out}
.hide-jobiki-Mmenu:hover{transform:rotate(90deg)}
.hide-jobiki-Mmenu{position:absolute;top:0;right:0;display:block;color:$(widget.title.color);font-size:26px;line-height:80px;text-align:center;cursor:pointer;z-index:20;padding:0 20px;-webkit-transition:transform ease-out .2s;-moz-transition:transform ease-out .2s;-ms-transition:transform ease-out .2s;-o-transition:transform ease-out .2s;transition:transform ease-out .2s;transform:rotate(0deg)}
.hide-jobiki-Mmenu:before{content:"\f00d";font-family:'Font Awesome 5 Free';font-weight:900}
.jobikis-open .jobikis-wrap,.jobikis-open .jobiki-Mmenu-p-flex{opacity:1}
.jobiki-Mmenu-p-flex{display:flex;flex-direction:column;opacity:0;justify-content:space-between;float:left;width:100%;height: calc(100% - 70px);transition:all ease-in-out .3s}
.jobiki-Mmenu{position:relative;float:left;width:100%;box-sizing:border-box;padding:25px}
.jobiki-Mmenu>ul{margin:0}
#jobikisMenu-pro .fa{padding:0 5px}
.jobiki-Mmenu .fa{margin:5px;padding:auto}
.jobiki-Mmenu .m-sub{display:none;padding:0}
.jobiki-Mmenu ul li{position:relative;display:block;overflow:hidden;float:left;width:100%;font-size:14px;font-weight:600;line-height:50px;margin:0;padding:0}
.jobiki-Mmenu>ul li ul{overflow:hidden}
.jobiki-Mmenu ul li a{color:$(submenu.color);padding:0 5px;display:block}
.jobiki-Mmenu>ul>li>a{text-transform:capitalize;border-bottom:1px solid rgba(255,255,255,0.2)}
.jobiki-Mmenu>ul>li.sub-tab>a:after,.jobiki-Mmenu>ul>li>ul>li.sub-tab>a:after{font-family:'Font Awesome 5 Free';font-weight:900;content:"\f078";font-size:12px;position:absolute;top:0;right:0;margin-right:10px;height:100%;flex-direction:row;align-items:center;justify-content:center}
.jobiki-Mmenu ul li.sub-tab.show>a:after{content:'\f077'}
.jobiki-Mmenu ul li a:hover,.jobiki-Mmenu ul li.sub-tab.show>a,.jobiki-Mmenu ul li.sub-tab.show>.submenu-toggle{color:fff}
.jobiki-Mmenu>ul>li>ul>li a:before{content:"\2022";font-family:'Font Awesome 5 Free';font-style:normal;font-weight:700;color:#fff;font-size:15px;padding-right:5px}
.jobiki-Mmenu>ul>li>ul>li a{font-size:13px;font-weight:600;color:$(submenu.color);background:rgba(255,255,255,0.12);padding:0 0 0 35px;border-bottom:1px solid rgba(255,255,255,0.2)}
.jobiki-Mmenu>ul>li>ul>li>ul>li>a{padding:0 0 0 30px}
.jobiki-Mmenu ul>li>.submenu-toggle:hover{color:$(menu.hover.color)}
.job-media{position:relative;float:left;margin:0 0 0 25px}
.job-media ul{display:block;text-align:center;margin:0}
.job-media ul li{display:inline-block;margin:0 5px}
.job-media ul li a{display:block;font-size:20px;color:$(main.menu);padding:0 5px}
.job-media ul li a:hover{opacity:1}
.fixed-nos{position:fixed;top:-56px;left:0;width:100%;z-index:990;transition:top .17s ease}
.job-hero.show{top:0;box-shadow:0 0 20px rgba(0,0,0,.15)}
.jobikis-open .fixed-nos{top:0}
.jobikis-open,.active-search{overflow:hidden;left:0;right:0}
.search-wrap{position: relative; display: flex; height: 56px; align-items: center; z-index: 11; margin: 0; }
.job-find-shadow.job-find-shadow-show .job-find-closer{display:block}
.search-container input::-webkit-input-placeholder{color:rgba(255,255,255,0.63)}
.job-find{color: $(submenu.color); top: 0; right: 0; width: 40px; height: 40px; font-size: 20px; text-align: center; line-height: 40px; cursor: pointer; z-index: 20; padding: 0; margin: 0; transition: margin .25s ease;}
.job-find:before{content:"\f002";font-family:'Font Awesome 5 Free';font-weight:900}
.job-find-shadow.job-find-shadow-show{visibility:visible;display:block;z-index:9999;transform:scale(1)}
.job-find-shadow{background:$(menu.color);background:-moz-linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);background:-webkit-linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);background:linear-gradient(90deg,$(menu.color) 0,$(menu.first.color) 100%);opacity:.99;width:100%;height:100%;position:fixed;top:0;left:0;display:block;visibility:hidden;z-index:999999;transform:scale(0);text-align:center;-webkit-transition:all .4s cubic-bezier(.79,.14,.15,.86);-moz-transition:all .5s cubic-bezier(.79,.14,.15,.86);-o-transition:all .5s cubic-bezier(.79,.14,.15,.86);transition:all .5s cubic-bezier(.79,.14,.15,.86)}
.job-find-closer{position:absolute;right:20px;top:35px;padding:20px;font-size:30px;-webkit-transition:transform ease-out .2s;-moz-transition:transform ease-out .2s;-ms-transition:transform ease-out .2s;-o-transition:transform ease-out .2s;transition:transform ease-out .2s;transform:rotate(0deg);color:$(widget.title.color)}
.job-find-closer:after{content:"\f00d";font-family:'Font Awesome 5 Free';font-weight:900}
.job-find-closer:hover{transform:rotate(90deg)}
input.search-input{background-color:transparent;border:0;text-align:start;font-size:35px;padding:20px;color:#fff;-webkit-transition:all .3s ease-out;-moz-transition:all .3s ease-out;-ms-transition:all .3s ease-out;-o-transition:all .3s ease-out;transition:all .3s ease-out}
.search-container-wrapper .fa-search{font-size:25px;position:absolute;right:20px;top:20px;color:rgba(255,255,255,0.65);-webkit-transition:all .2s ease-out;-moz-transition:all .2s ease-out;-ms-transition:all .2s ease-out;-o-transition:all .2s ease-out;transition:all .2s ease-out}
.search-container-wrapper form{position:relative}
form.search-container{max-width:100%;border:1px solid rgba(255,255,255,0.49)}
input.search-input[type=text]{width:83%;height:60px;display:block}
.search-msg{text-align:center;font-size:18px;color:rgba(255,255,255,0.96);padding:5px 0;margin:10px 0;border-bottom:1px dashed rgba(255 255 255 / 36%)}
.search-container-wrapper{display:inline-block;max-width:1000px;margin:0 10px;vertical-align:middle;text-align:center;font-size:18px;-webkit-transform:scale(0.9);-moz-transform:scale(0.9);-ms-transform:scale(0.9);-o-transform:scale(0.9);transform:scale(0.9);ms-transform:scale(0.9);opacity:0;visibility:hidden;-webkit-transition:all ease-in-out .3s;-moz-transition:all ease-in-out .3s;-ms-transition:all ease-in-out .3s;-o-transition:all ease-in-out .3s;transition:all ease-in-out .3s}
.job-find-shadow-show .search-container-wrapper{opacity:1;visibility:visible;-webkit-transform:scale(1);-moz-transform:scale(1);-ms-transform:scale(1);-o-transform:scale(1);transform:scale(1);ms-transform:scale(1)}
.search-container-wrapper input[type="submit"]{position:absolute;width:70px;height:60px;background-color:transparent;border:0;right:-20px;top:-20px;border-left:1px solid rgba(255,255,255,0.49);cursor:pointer;-webkit-appearance:button;outline:0}
.job-find-shadow:before{content:'';display:inline-block;height:100%;vertical-align:middle}
.search-input{position:relative;padding:20px;padding-bottom:10px}
.search-input input{border-radius:10px;padding:5px 10px;width:98%;border:2px solid #eee}
#hidden-widget-container,.hide,.hidden-widgets{display:none;visibility:hidden}

.breaking-job-news{position:relative;margin:5px auto;background: rgb(0 0 0 / .03);border: 1px solid rgb(0 0 0 / .19);overflow: hidden; }
.breaking-job-news .widget{display:block;height:25px;padding:5px 0;margin:0}
.breaking-job-news .widget>.widget-title{display:block;position:relative;float:left;color:#fff;background: $(main.color);font-size:11px;text-transform:uppercase;height:25px;line-height:25px;padding:0 10px;margin:0 10px 0 5px;}
.breaking-job-news .widget>.widget-title>h3{font-size:11px;font-weight:700;line-height:25px;margin:0}
.breaking-job-news .widget>.widget-title>h3:before{content:'\f0e7';font-family:'Font Awesome 5 Free';float:left;font-size:11px;font-weight:900;margin:0 5px 0 0;}
.breaking-job-news .widget-content{position: relative;display:none;height: 30px; justify-content: space-between; flex: 1; margin: 0;overflow: hidden;}
.breaking-ticker{box-sizing:border-box;float:left}
.breaking-job-news .open-iki{display:flex!important}
.breaking-post .entry-title{height:30px;font-size:13px;font-weight:400;line-height:30px;margin:0;padding:0;overflow:hidden}
.breaking-post .entry-title a{position: relative;display: block;overflow: hidden;font-size: 15px;color: #000000;}
.breaking-ticker .active{opacity:1;visibility:visible;transform:translate3d(0,0,0);pointer-events:initial}
.breaking-post{position:absolute;top:0;left:0;width:100%;opacity:0;visibility:hidden;transform:translate3d(10px,0,0);pointer-events:none;transition:all .80s ease}
.breaking-job-news .breaking-new-news{position:relative;height:25px;display:flex;justify-content:flex-end;flex:1;align-items: center;margin:0}
.mydivs-bt{display:flex;flex-direction:row;align-items:center;justify-content:space-around;margin:0;height:30px}
.mydivs-bt>a{display:flex;width:20px;height:20px;line-height:20px;font-size:12px;text-align:center;margin:0 2px;padding:5px;cursor:pointer;color:#fff;background:$(main.color)}
.mydivs-bt>a:hover{background:#666;}
.mydivs-bt .prev:before{content:'\f053'}
.mydivs-bt .next:before{content:'\f054'}
.mydivs-bt a:before{display:block;font-family:'Font Awesome 5 Free';margin:auto;text-align:center;font-weight:900}

/*-- Post Snip Starts here --*/
.no-posts{float:left;width:100%;height:100px;line-height:100px;text-align:center}
.piki-load .no-posts{line-height:60px;color:$(title.color)}
.post-snip{overflow:hidden;--meta-fontcolor:var(--light-solid-color);font-size:11px;font-weight:500;padding:0 2px 0}
.post-snip .post-author,.post-snip .post-date{float:none;display:inline-block;margin:0 10px 0 0}
.post-snip .post-author{font-weight:600;}
.post-snip .post-date:before{font-family:'Font Awesome 5 Free';font-weight:400;margin:0 3px 0 0}
.post-snip .post-author {color: #333;}
.type-slider .post-snip .post-author,.type-slider .post-snip .post-date, .mega-hero .item0 .post-snip .post-author, .mega-hero .item0 .post-snip .post-date, .job-mposts-mgs .post-snip .post-author, .job-mposts-mgs .post-snip .post-date{color: #c1c1c1;}
.post-snip .post-author:before{content:'By -';margin:0 3px 0 0;font-weight: normal; }
.post-snip .post-date:before{content:'\f017'}
.post-snip a{color:#333;transition:color .40s}
.item-post .post-snip .author-image{overflow: hidden; position: relative; display: inline-block; width: 25px; vertical-align: middle; height: 25px; background-color: var(--light-author-color); padding: 1px; margin: 0 3px 0 0; border: 1px solid rgb(0 0 0 / 25%); border-radius: 100%; box-shadow: 0px 0px 4px 3px rgba(0 0 0 / 13%); }
.read-more{position:relative;display:block;background:#fff;color:#000;font-size:13px;font-weight:600;text-align:left;float:left;padding:2px 10px;border:1px solid rgb(0 0 0 / 25%);box-shadow:0 2px 8px rgb(0 0 0 / 12%);border-radius:15px;margin:0 5px 10px}
.read-more:before{content:'\f06e';font-family:'Font Awesome 5 Free';font-weight:400;margin:0 3px 0 0}
.piki-ads{ display:block; border: 4px solid #dedede; background-color: #f7f7f7; text-align: center; line-height: 85px; font-size:13px; font-style: italic; font-weight: 700; color: #737373; }
.piki-ads-res{ display:block; border: 4px solid #dedede; background-color: #f7f7f7; text-align: center; line-height: 205px; font-size:13px; font-style: italic; font-weight: 700; color: #737373; }
.main-title{display: flex;justify-content: space-between;align-items: center;position: relative;margin: 0 0 14px}
a.view-all{color:#000;padding:1px 10px;font-size:12px}
a.view-all:hover{color:$(main.color)}
.jobiki-box .widget{position:relative;display:none;overflow:hidden;width:100%;box-sizing:border-box;padding:15px;margin:0 0 10px;background:rgb(0 0 0 / 0.03);border-radius: 5px;border: 1px solid rgb(0 0 0 / 19%);margin: 0 0 10px;}
.jobiki-post{display:flex;justify-content:space-between;flex-wrap:wrap}
.jobiki{width:32%;background:#fff;border-radius:0;margin-bottom:20px;position:relative}
.jobiki-main:after{content:"";position:absolute;left:0;right:0;bottom:0;height:66%;background-image:linear-gradient(to bottom,transparent,rgba(0,0,0,0.9));-webkit-backface-visibility:hidden;backface-visibility:hidden;z-index:2;opacity:1;margin:0;transition:opacity .25s ease}
.jobiki-box .entry-title,.sidebar .entry-title,.footer-post .entry-title,.job-related .entry-title{display:block;text-decoration:none;font-weight:600;line-height:1.2em;font-size:13px;padding:4px 0 0;margin:auto}
.job-related .job-wmr-creative .job-mposts-Pikirt {width: calc((100% - 10px) / 2);}
.entry-title a{display:block;color:$(body.post.color)}
.entry-title a:hover{color:$(main.hover)}
.type-slider .entry-title a, .mega-hero .item0 .entry-title a, .job-mposts-mgs .entry-title a{display:block;color:$(widget.title.color)}
.footer-post .entry-title a{display:block;font-size:13px;color:$(footer.post.color)}
.footer-post .entry-title a:hover,a.simple-viewmore:hover,.job-mposts-mgs .entry-title a:hover,.post-filter .entry-title a:hover{color:$(title.hover)}
.post-filter .entry-title a{font-size:13px;font-weight:600;line-height:1.2em}
.jobiki-post .item0 .post-tag,.jobiki-post .item0 .post-author{display:block}
