.featured-post-pro .widget .widget-content .feature-buttons{width:calc((100% - 60px) / 4);height:43px;line-height:43px;text-align:center;overflow:hidden;position:relative;display:block;border-radius:7px;border:1px solid #2359b1;background:rgb(45 115 230 / .09);margin:10px auto;box-shadow:0 4px 8px 0 rgb(0 0 0 / .10)}
.featured-post-pro .widget .widget-content .feature-buttons a{color:#255ebb;font-size:16px;font-weight:700;text-shadow:1px 2px 4px rgb(0 0 0 / .25)}
.featured-post-pro .widget .widget-content .feature-buttons:hover{background:rgb(255 0 0 / .11);border:1px dashed rgb(165 0 0 / .50)}
.featured-post-pro .widget .widget-content .feature-buttons a:hover{color:#ae0000}

/* Bouncing Scroll Animation */
.featured-post-pro .widget .widget-content marquee {
    display: none;
}

.featured-post-pro .widget .widget-content .marquee-container {
    width: 100%;
    overflow: hidden;
    position: relative;
    margin: 5px auto;
}

.featured-post-pro .widget .widget-content .marquee-content {
    display: inline-block;
    white-space: nowrap;
    animation: bounce-scroll 8s ease-in-out infinite;
    animation-direction: alternate;
}

.featured-post-pro .widget .widget-content .marquee-content a {
    color: #255ebb;
    font-size: 18px;
    font-weight: 700;
    margin: 0 40px 0 0;
    text-shadow: 1px 2px 4px rgb(0 0 0 / .25);
    display: inline-block;
}

.featured-post-pro .widget .widget-content .marquee-content a:after {
    content: "||";
    color: #000;
    margin: 0 0 0 40px;
    font-size: 20px;
}

.featured-post-pro .widget:nth-child(even) .marquee-content a:nth-child(odd) {
    color: #ca0000;
}

.featured-post-pro .widget:nth-child(odd) .marquee-content a:nth-child(even) {
    color: #1cab00;
}

@keyframes bounce-scroll {
    0% {
        transform: translateX(0);
    }
    100% {
        transform: translateX(calc(-100% + 100vw));
    }
}

.featured-post-pro .widget .widget-content .marquee-container:hover .marquee-content {
    animation-play-state: paused;
}
.featured-post-pro .widget:nth-child(even) .widget-content marquee a:nth-child(odd){color:#ca0000}
.featured-post-pro .widget:nth-child(odd) .widget-content marquee a:nth-child(even){color:#1cab00}
