.blog-pager .page-active,.blog-pager a:hover{background-color:$(main.color);color:#fff;border-color:$(main.color)}
.blog-pager .page-prev:before,.blog-pager .page-next:before{font-family:'Font Awesome 5 Free';font-size:11px;font-weight:900}
.blog-pager .page-prev:before{content:'\f053'}
.blog-pager .page-next:before{content:'\f054'}
.blog-pager .blog-pager-newer-link,.blog-pager .blog-pager-older-link{float:left;display:inline-block;width:auto;padding:0 10px;margin:0}
.blog-pager .blog-pager-older-link{float:right}
.archive #blog-pager,.home .blog-pager .blog-pager-newer-link,.home .blog-pager .blog-pager-older-link{display:none}
.blog-post-comments{display:none;overflow:hidden;padding:15px;margin:0 0 10px;box-sizing:border-box;background: rgb(0 0 0 / 0.03);border-radius: 5px;border: 1px solid rgb(0 0 0 / 0.19);}
.blog-post-comments .comments-title{margin:0 0 20px}
.all-comments{float:right;position:relative;color:#333}
.comments-system-disqus .comments-title,.comments-system-facebook .comments-title{margin:0}
#comments{margin:0}
.comments{display:block;clear:both;margin:0;color:$(title.color)}
.comments .comment-thread>ol{padding:0}
.comments>h3{font-size:13px;font-weight:400;font-style:italic;padding-top:1px}
.comments .comments-content .comment{list-style:none;margin:0;padding:0 0 8px}
.comments .comments-content .comment:first-child{padding-top:0}
.facebook-tab,.fb_iframe_widget_fluid span,.fb_iframe_widget iframe{width:100%!important}
.comments .item-control{position:static}
.comments .avatar-image-container{float:left;overflow:hidden;position:absolute}
.comments .avatar-image-container,.comments .avatar-image-container img{height:35px;max-height:35px;width:35px;max-width:35px;border-radius:100%}
.comments .comment-block{overflow:hidden;    border: 1px solid #dcdcdc; padding: 10px;}
.comments .comment-block,.comments .comments-content .comment-replies{margin:0 0 0 50px}
.comments .comments-content .inline-thread{padding:0}
.comments .comment-actions{float:left;width:100%;position:relative;margin:0}
.comments .comments-content .comment-header{font-size:15px;display:block;overflow:hidden;clear:both;margin:0 0 3px;padding:0 0 5px;border-bottom: 1px solid #dfdfdf;}
.comments .comments-content .comment-header a{color:$(title.color);transition:color .40s}
.comments .comments-content .comment-header a:hover{color:$(main.hover)}
.comments .comments-content .user{font-style:normal;font-weight:700}
.comments .comments-content .icon.blog-author:after{content:"\f058";font-family:'Font Awesome 5 Free';font-size:18px;color:#0093e6;font-weight:500;text-transform:none;margin:0 0 0 4px}
.comments .comments-content .comment-content{float:left;font-family:var(--text-font);font-size:13px;color:#5e5e5e;font-weight:400;text-align:left;line-height:1.4em;width: 100%; padding: 20px 10px; background: #e1e1e1;margin:5px 0 9px}
.comment-content .video-frame{position:relative;width:100%;padding:0;padding-top:56%}
.comment-content .video-frame iframe{position:absolute;top:0;left:0;width:100%;height:100%}
.comments .comment .comment-actions a{margin-right:5px;padding:2px 5px;color:$(title.color);font-weight:400;background-color:#f2f2f2;font-size:10px;transition:all .30s ease}
.comments .comment .comment-actions a:hover{color:#fff;background-color:$(main.color);border-color:$(main.color);text-decoration:none}
.comments .comments-content .datetime{float:right;--meta-fontfont-size:11px;font-weight:400;color:#aaa;position:relative;padding:0 1px;margin:4px 0 0;display:block}
.comments .comments-content .datetime a,.comments .comments-content .datetime a:hover{color:#6e6e6e}
.comments .thread-toggle{margin-bottom:4px}
.comments .thread-toggle .thread-arrow{height:7px;margin:0 3px 2px 0}
.comments .thread-count a,.comments .continue a{transition:opacity .40s}
.comments .thread-count a:hover,.comments .continue a:hover{opacity:.8}
.comments .thread-expanded{padding:5px 0 0}
.comments .thread-chrome.thread-collapsed{display:none}

.thread-expanded .thread-count a,.loadmore{display:none;}
.comments .comments-content .comment-thread{margin:0}
.comments .continue a{padding:0 0 0 60px;font-weight:400}
.comments .comments-content .loadmore.loaded{margin:0;padding:0}
.comments .comment-replybox-thread{margin:0}
.comments .comments-content .loadmore,.comments .comments-content .loadmore.loaded,.blog-post-comments.comments-system-facebook .all-comments,.blog-post-comments.comments-system-disqus .all-comments{display:none}
#comment-editor{margin:0 0 20px}
.comments-msg-alert { position: relative; display: block; font-size: 12px; padding: 0 0 10px; color: #dc0000; border-bottom: 1px solid rgba(206 206 206 / 50%); }
.dark #comments{background:transparent}
.dark #content{background:transparent}
.dark #comments .comment-block .comment-content{color:#fff}
.dark #comments .comment-block{background:transparent;color:#fff}
.dark #blog-pager a.home-link{background:#222;color:#e3e3e3;border:3px solid #e3e3e3}
.dark #comments h4,.dark .job-related h4{color:rgba(255,255,255,.7);border-color:rgba(255,255,255,0.1)}

blockquote{font-style:italic;padding:10px;margin:0;border-left:4px solid $(main.color);color:var(--black-color);border:1px dashed #e4e4e4;background:#f6f6f6;border-top-left-radius:20px;border-bottom-right-radius:20px}
blockquote{font-style:italic;color:var(--black-color);border-left:5px solid $(main.color);margin-left:0;padding:10px 15px}
blockquote:before{content:'\f10d';display:inline-block;font-family:'Font Awesome 5 Free';font-style:normal;font-weight:900;line-height:1;-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;margin-right:10px;color:$(main.color)}
blockquote:after{content:'\f10e';display:inline-block;font-family:'Font Awesome 5 Free';font-style:normal;font-weight:900;line-height:1;-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;margin-left:10px;color:$(main.color)}
.post-body ul{line-height:1.5em;font-weight:400;padding:0 0 0 15px;margin:10px 0}
.post-body li{margin:5px 0;padding:0;line-height:1.5em}
.post-body ol>li{counter-increment:piki;list-style:none}
.post-body ol>li:before{display:inline-block;content:counters(piki,'.')'.';margin:0 5px 0 0}
.post-body ol{counter-reset:piki;padding:0 0 0 15px;margin:10px 0}
.post-body ul li{list-style:disc outside !important}
.post-body u{text-decoration:underline}
.post-body a{transition:color .30s ease}
.post-body strike{text-decoration:line-through}
.post-body .video-frame {position: relative;width: 100%;padding: 50% 0 0;}
.post-body .video-frame iframe {position: absolute;top: 0;left: 0;width: 100%;height: 100%;}
.widget .post-body li{margin:5px 0;padding:0px;line-height:1.8}
.contact-form{overflow:hidden}
.contact-form .widget-title{display:none}
.contact-form .contact-form-name{width:calc(50% - 5px)}
.contact-form .contact-form-email{width:calc(50% - 5px);float:right}
.sidebar .widget{position:relative;overflow:hidden;width:100%;box-sizing:border-box;padding:15px;margin:0 0 10px;background:rgb(0 0 0 / 0.03);border-radius: 5px;border: 1px solid rgb(0 0 0 / 0.19);}
.post-filter-wrap{position:relative;overflow:hidden;width:100%;box-sizing:border-box;padding:15px;margin:0 0 10px;background:rgb(0 0 0 / 0.03);border-radius: 5px;border: 1px solid rgb(0 0 0 / 0.19);}
.sidebar .widget-content{float:left;width:100%;margin:0;box-sizing:border-box;padding:0}
ul.socialFilter{margin:0 -5px}
.socialFilter a:before{font-style:normal;line-height:40px;-webkit-font-smoothing:antialiased;margin-right:-12px;width:40px;height:40px;text-align:center;float:left;border-right:1px solid rgba(255,255,255,0.24);background: rgba(255 255 255 / 23%);font-size:22px;vertical-align:middle}
.dark .sidebar .widget{background:transparent}
.dark .queryMessage, .dark .about-author{border: 1px solid #292929;}
.dark #PopularPosts1 ul li a:hover{background:transparent}
.dark #footer-wrapper{background-color: #090512;}
.dark .job-cont-creative, .dark .darkmode-box .hero-dark-flow, .dark .post-filter, .dark .darkHero-post, .dark .cloud-label li a {background:#0f0f17; box-shadow: none;}
.dark .socialFilter li a{border:none;}
.dark #footer-nos .Image .image-caption{color: #aeaeae;}
.dark .copyright-text {color: #686868;}
.dark #social a:hover{background:transparent;color:#fff}
.dark .search-icon a, .dark .tg, .dark .tg td{background:transparent}
{transparent}
.socialFilter li{float:left;width:50%;box-sizing:border-box;padding:0 5px;margin:10px 0 0}
.socialFilter li:nth-child(1),.socialFilter li:nth-child(2){margin-top:0}
.socialFilter li a{display:block;height:40px;color:#fff;font-size:14px;text-align:center;line-height:40px;border:1px solid #eee;border-radius: 5px;}
.socialFilter li a:hover,.search-container-wrapper .fa-search:hover,.jobiki-Mmenu ul li a:hover,.job-media ul li a:hover{opacity: 0.8}
.list-label li{position:relative;display:block;padding:7px 0;border-top:1px dotted #ebebeb}
.list-label li:first-child{padding-top:0;border-top:0}
.list-label li:last-child{padding-bottom:0;border-bottom:0}
.list-label li a{display:block; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;color:$(title.color);font-size:12px;font-weight:400;text-transform:capitalize;transition:all .30s ease}
.list-label li a:before{content:"\f101";float:left;color:$(title.color);font-weight:900;font-family:'Font Awesome 5 Free';font-size:12px;line-height:12px;margin:5px 4px 0 0;transition:color .5s}
.list-label li a:hover{color:$(main.hover); padding-left:25px;transition:all .30s ease}
#footer-wrapper .list-label li a:before{color:$(icon.color)}
.Text .widget-content{font-family:var(--text-font);font-size:14px;color:$(title.color);margin:0}
.list-label .label-count{position:relative;float:right;width:16px;height:16px;background-color:$(main.color);color:#fff;font-size:11px;font-weight:400;text-align:center;line-height:16px}
.cloud-label li{position:relative;float:left;margin:0 5px 5px 0}
.cloud-label li a{display:block;height:26px;overflow: hidden;background-color:$(main.tag);color:$(widget.title.color);font-size:12px;line-height:26px;border-radius: 10px;font-weight:400;padding:0 10px;border:1px solid #eee;transition:all .30s ease}
.cloud-label li a:before{content:"\f101";float:left;color:$(icon.color);font-weight:900;font-family:'Font Awesome 5 Free';font-size:12px;margin:0 4px 0 0;}
.cloud-label li a:hover{background-color:$(main.hover);color:$(widget.title.color);transition:all .20s ease;}
.cloud-label .label-count{display:none}
.sidebar .FollowByEmail>.widget-title>h3{margin:0}
.FollowByEmail .widget-content{position:relative;background-color:#cccccc;text-align:center;font-weight:400;box-sizing:border-box;padding:20px 20px 5px;border-radius:2px;border:1px solid #b0b0b0}
.FollowByEmail .widget-content>h3{font-size:16px;color:$(title.color);font-weight:700;text-transform:uppercase;margin:0 0 13px}
.FollowByEmail .before-text{font-size:13px;letter-spacing: 1px;line-height:1.5em;margin:0 0 15px;display:block;padding:0 10px;overflow:hidden}
.FollowByEmail .follow-by-email:before{content: '\f0f3'; position: absolute; font-family: 'Font Awesome 5 Free'; color: #fff; top: 0; left: 50%; width: 36px; overflow: hidden; height: 36px; background-color: $(main.color); font-size: 18px;font-weight: 900; line-height: 36px; text-align: center; transform: translate(-50%,-30%); margin: 0; border-radius: 50%;}
.FollowByEmail .follow-by-email-inner{position:relative}
.FollowByEmail{clear:both}
.follow-by-email-title{font-size:17px; font-weight:700; padding:7px ;margin:15px 0px;color:#000}
.FollowByEmail .follow-by-email-inner .follow-by-email-address{width:100%;height:32px;color:$(title.color);font-size:11px;font-family:inherit;padding:0 10px;margin:0 0 10px;box-sizing:border-box;border:1px solid #eee;transition:ease .40s}
.FollowByEmail .follow-by-email-inner .follow-by-email-submit{width:100%;height:32px;font-family:inherit;border-radius:4px;font-size:11px;color:#fff;background-color:$(main.color);text-transform:uppercase;text-align:center;font-weight:500;cursor:pointer;margin:0;border:0;transition:opacity .30s ease}
.FollowByEmail .follow-by-email-inner .follow-by-email-submit:hover{opacity:.85;background:$(main.hover)}
.Follow-by-alert { position: relative; display: block; font-size: 12px; text-align: left; margin: 10px 0 0; }
#ArchiveList ul.flat li{color:$(title.color);font-size:13px;font-weight:400;padding:7px 0;border-bottom:1px dotted #eaeaea}
#ArchiveList ul.flat li:first-child{padding-top:0}
#ArchiveList ul.flat li:last-child{padding-bottom:0;border-bottom:0}
#ArchiveList .flat li>a{display:block;color:$(title.color);transition:color .40s}
#ArchiveList .flat li>a:hover{color:$(main.hover)}
#ArchiveList .flat li>a:before{content:"\f054";font-family:'Font Awesome 5 Free';float:left;color:#161619;font-size:7px;font-weight:400;margin:5px 2px 0 0;display:inline-block;transition:color .30s}
#ArchiveList .flat li>a>span{position:relative;background-color:$(main.color);color:#fff;float:right;width:16px;height:16px;font-size:10px;font-weight:400;text-align:center;line-height:15px}
.PopularPosts .post{overflow:hidden;margin:20px 0 0}
.PopularPosts .post:first-child{padding:0;margin:0;border:0}
.PopularPosts .post-filter-link{position:relative;width:80px;height:70px;float:left;overflow:hidden;display:block;vertical-align:middle;margin:0 12px 0 0;border-radius: 10px}
.PopularPosts .piki-hero-box{overflow:hidden}
.PopularPosts .entry-title{overflow: hidden;font-size:13px;font-weight:600;position: relative;  line-height: 1.4em;margin:0}
.PopularPosts .entry-title a{display:block;color:#000;padding:0;transition:color .40s}
.PopularPosts .post:hover .entry-title a{color:$(main.hover)}
.PopularPosts .post-date:before{font-size:10px}
.FeaturedPost .entery-category span{font-size:11px;}
.FeaturedPost .post-filter-link{display:block;position:relative;width:100%;height:250px;overflow:hidden;margin:0 0 10px}
.FeaturedPost .entry-title{font-size:14px;font-weight:600;overflow:hidden;line-height:1.2em;margin:0}
.FeaturedPost .entry-title a{color:$(title.color);display:block;transition:color .30s ease}
.FeaturedPost .entry-title a:hover{color:$(main.hover)}
.contact-form-widget form{font-weight:400;margin:15px}
.contact-form-name{float:left;width:100%;height:30px;font-family:inherit;font-size:13px;line-height:30px;box-sizing:border-box;padding:5px 10px;margin:0 0 10px;border:1px solid #b7b7b7;border-radius:2px}
.contact-form-email{float:left;width:100%;height:30px;font-family:inherit;font-size:13px;line-height:30px;box-sizing:border-box;padding:5px 10px;margin:0 0 10px;border:1px solid #b7b7b7;border-radius:2px}
.contact-form-email-message{float:left;width:100%;font-family:inherit;font-size:13px;box-sizing:border-box;padding:5px 10px;margin:0 0 10px;border:1px solid #b7b7b7;border-radius:2px}
.contact-form-button-submit{float:left;width:100%;height:30px;background-color:$(main.color);font-size:13px;color:#fff;line-height:30px;cursor:pointer;box-sizing:border-box;padding:0 10px;margin:10px 0;border:0;border-radius:2px;transition:background .30s ease}
.contact-form-button-submit:hover{background-color:$(main.hover)}
.contact-form-error-message-with-border{float:left;width:100%;background-color:#fbe5e5;font-size:11px;text-align:center;line-height:11px;padding:3px 0;margin:10px 0;box-sizing:border-box;border:1px solid #fc6262}
.contact-form-success-message-with-border{float:left;width:100%;background-color:#eaf6ff;font-size:11px;text-align:center;line-height:11px;padding:3px 0;margin:10px 0;box-sizing:border-box;border:1px solid #5ab6f9}
.contact-form-cross{margin:0 0 0 3px}
.contact-form-error-message,.contact-form-success-message{margin:0}
.BlogSearch .search-form {display: flex; border:1px solid #505050; padding:3px}
.BlogSearch .search-input{float:left;width:75%;height:40px;background-color:#fff;color:#000;font-weight:400;font-size:13px;line-height:30px;box-sizing:border-box;padding:5px 10px}
.BlogSearch .search-action{float:right;width:25%;height:40px;font-family:inherit;font-size:13px;line-height:40px;cursor:pointer;box-sizing:border-box;background-color:$(widget.background);color:#fff;padding:0 5px;border:0;border-radius:0 2px 2px 0;transition:background .30s ease}
.BlogSearch .search-action:hover{background-color:$(main.hover)}
.Profile .profile-img{float:left;width:80px;height:80px;margin:0 15px 0 0;transition:all .30s ease}
.Profile .profile-info >.profile-link{color:$(title.color);font-size:11px;margin:5px 0 0}
.Profile .profile-info >.profile-link:hover{color:$(main.hover)}
.Profile .profile-datablock .profile-textblock{display:none}
.widget-control .LinkList ul li,.widget-control .PageList ul li{width:calc(50% - 5px);padding:7px 0 0}
#footer-wrapper .widget-control .PopularPosts{border:none}
.widget-control .LinkList ul li:nth-child(odd),.widget-control .PageList ul li:nth-child(odd){float:left}
.widget-control .LinkList ul li:nth-child(even),.widget-control .PageList ul li:nth-child(even){float:right}
.widget-control .LinkList ul li a,.widget-control .PageList ul li a{ color: #000000; font-size: 13px; font-weight: 500; background: #d7d7ee; width:auto; padding:3px 5px; margin: auto; white-space: nowrap; display: block; overflow: hidden; text-overflow: ellipsis; transition: color .30s ease;}
.widget-control .LinkList ul li a:before,.widget-control .PageList ul li a:before{content:"\2022";float:left;color:#000;font-weight:900;font-family:'Font Awesome 5 Free';font-size:12px;margin:0 4px 0 0}
.widget-control .LinkList ul li a:hover,.widget-control .PageList ul li a:hover{color:$(main.hover);transition:all .5s ease;border-radius:4px}
.widget-control .LinkList ul li:first-child,.widget-control .LinkList ul li:nth-child(2),.widget-control .PageList ul li:first-child,.widget-control .PageList ul li:nth-child(2){padding:0}

/*-- Footer Section Codes --*/
#footer-wrapper{background-color:$(footer.background.color)}
div#footer-wrapper .contact-form-widget form {color: #fff;}
#footer-wrapper .container{position:relative;overflow:hidden;margin:0 auto;box-sizing:border-box;padding:10px 20px}
.footer-widgets-wrap{position:relative;display:flex;margin:0 -15px}
#footer-wrapper .footer{display:inline-block;float:left;width:33.33333333%;box-sizing:border-box;padding:0 15px}
#footer-wrapper .footer .widget{float:left;width:100%;padding:5px 0;margin:10px 0 0}
#footer-wrapper .footer .Text{margin:10px 0 0}
#footer-wrapper .footer .widget:first-child{margin:0}
.footer .widget>.widget-title>h3{position:relative;font-family:var(--title-font);color:$(footer.widget.title);font-size:14px;font-weight:700;line-height:14px;border-bottom:1px solid #767676;text-transform:uppercase;padding: 0 0 5px;margin:15px 0 25px}
.footer .custom-widget .entry-title a,.footer .PopularPosts .entry-title a,.footer .FeaturedPost .entry-title a,.footer .PageList ul li a,.footer .Profile .profile-info>.profile-link{color:$(footer.post.color)}
.footer .LinkList ul li a{color:#000}
.footer .custom-widget .entry-title a:hover,.footer .PopularPosts .entry-title a:hover,.footer .FeaturedPost .entry-title a:hover,.footer .LinkList ul li a:hover,.footer .PageList ul li a:hover,.footer .Profile .profile-info>.profile-link:hover{color:$(main.hover)}
.footer .no-posts{color:$(footer.post.color)}
.footer .FollowByEmail .widget-content>h3{color:$(footer.post.color)}
.footer .FollowByEmail .widget-content{background-color:rgba(255,255,255,0.05);border-color:rgba(255,255,255,0.05)}
.footer .FollowByEmail .before-text,#footer-wrapper .footer .Text{color:#aaa}
.footer .FollowByEmail .follow-by-email-inner .follow-by-email-submit:hover{background:$(main.hover)}
.footer .FollowByEmail .follow-by-email-inner .follow-by-email-address{background-color:rgba(255,255,255,0.05);color:$(footer.post.color);border-color:rgba(255,255,255,0.05)}
.footer #ArchiveList .flat li>a{color:$(footer.post.color)}
.footer .list-label li,.footer .BlogArchive #ArchiveList ul.flat li{border-color:rgba(255,255,255,0.05)}
.footer .list-label li:first-child{padding-top:0}
.footer .list-label li a,.footer .list-label li a:before,.footer #ArchiveList .flat li>a,.footer #ArchiveList .flat li>a:before{color:$(footer.post.color)}
.footer .list-label li>a:hover,.footer #ArchiveList .flat li>a:hover{color:$(main.hover)}
.footer .list-label .label-count,.footer #ArchiveList .flat li>a>span{background-color:rgba(255,255,255,0.05);color:$(footer.post.color)}
.footer .cloud-label li a{border-color:rgba(255,255,255,0.05);color:$(footer.post.color)}
.footer .cloud-label li a:hover{background-color:$(main.color);color:#fff}
.footer .BlogSearch .search-input{background-color:rgba(255,255,255,0.05);color:$(footer.post.color);border-color:rgba(255,255,255,0.05)}
.footer .contact-form-name,.footer .contact-form-email,.footer .contact-form-email-message{background-color:rgba(255,255,255,0.05);color:$(footer.post.color);border-color:rgba(255,255,255,0.05)}
.footer .BlogSearch .search-action:hover,.footer .FollowByEmail .follow-by-email-inner .follow-by-email-submit:hover,.footer .contact-form-button-submit:hover{background-color:#3c3c3c}
.footer .contact-form-button-submit{background:$(main.hover)}

/*-- Back to Top --*/
.backTop{display:none;z-index:1010;width:32px;height:32px;position:fixed;bottom:25px;right:25px;cursor:pointer;overflow:hidden;font-size:13px;color:#fff;text-align:center;line-height:32px}
.backTop:before{content:'';position:absolute;top:0;left:0;right:0;bottom:0;background-color:$(main.hover);opacity:.5;transition:opacity .30s ease}
.backTop:after{content:'\f077';position:relative;font-family:'Font Awesome 5 Free';font-weight:900;opacity:.8;transition:opacity .30s ease}
.backTop:hover:before,.backTop:hover:after,.jobikis-open .backTop:after,.jobikis-open .backTop:before{opacity:1}

/*-- Custom 404 Error Page --*/
.error404 #feed-view{width:100%!important;margin:0!important}
.error404 #sidebar-container{display:none}
.errorPage{color:$(title.color);text-align:center;padding:80px 0 100px}
.errorPage h3{font-size:160px;line-height:1;margin:0 0 30px}
.errorPage h4{font-size:25px;margin:0 0 20px}
.errorPage p{margin:0 0 10px}
.errorPage a{display:block;color:$(main.color);padding:10px 0 0}
.errorPage a i{font-size:20px}
