b:if.script:
//
  document.addEventListener("DOMContentLoaded", function() {
    var jobListings = document.querySelectorAll('.job-listing');
    jobListings.forEach(function(listing) {
      var hiddenBody = listing.querySelector('.hidden-post-body');
      if (hiddenBody) {
        var tempDiv = document.createElement('div');
        tempDiv.innerHTML = hiddenBody.innerHTML;
        var dataTable = tempDiv.querySelector('.job-details-data table');
        if (dataTable) {
          var detailsHtml = '';
          var rows = dataTable.querySelectorAll('tr');
          rows.forEach(function(row) {
            var cells = row.querySelectorAll('td');
            if (cells.length === 2) {
              var label = cells[0].textContent.replace(':', '').trim();
              var value = cells[1].textContent.trim();
              detailsHtml += "<div class='job-detail'><span class='job-detail-label'>" + label + ": </span><span>" + value + "</span></div>";
            }
          });
          listing.querySelector('.job-listing-details').innerHTML = detailsHtml;
        }
      }
    });
  });
//

