$(document).ready(function() {

    // Run only on post pages
    if ($('body').hasClass('item-view')) {

        // Get all paragraphs inside the post body
        var paragraphs = $('.post-body p');

        // Ensure at least 2 paragraphs exist (so box appears in middle)
        if (paragraphs.length > 1) {

            // Choose a random paragraph except the first one
            var randomIndex = Math.floor(Math.random() * (paragraphs.length - 1)) + 1;
            var injectionPoint = paragraphs.eq(randomIndex);

            // Get first label of this post
            var firstLabel = $('.label-container .label-link').first().text().trim();

            if (firstLabel) {

                var currentPostUrl = window.location.href;

                // Fetch up to 10 posts from same label
                var feedUrl = "/feeds/posts/default/-/" + encodeURIComponent(firstLabel) + "?alt=json-in-script&max-results=10";

                $.ajax({
                    url: feedUrl,
                    type: 'get',
                    dataType: 'jsonp',

                    success: function(data) {
                        if (!data.feed.entry) return;

                        // Build a list of posts (EXCLUDING current one)
                        var relatedPosts = [];

                        data.feed.entry.forEach(function(entry) {
                            var postTitle = entry.title.$t;
                            var postUrl = "";

                            entry.link.forEach(function(link) {
                                if (link.rel === 'alternate') {
                                    postUrl = link.href;
                                }
                            });

                            // Exclude current post
                            if (postUrl !== currentPostUrl) {
                                relatedPosts.push({
                                    title: postTitle,
                                    url: postUrl
                                });
                            }
                        });

                        if (relatedPosts.length > 0) {
                            // Select a random related post
                            var randomPost = relatedPosts[Math.floor(Math.random() * relatedPosts.length)];

                            // Create HTML block
                            var htmlToInject =
                                '<div class="auto-internal-link-box" style="margin:20px 0;padding:12px;border-left:4px solid #0077ff;background:#f5f8ff;">' +
                                '<strong>Also Read:</strong> <a href="' + randomPost.url + '">' + randomPost.title + '</a>' +
                                '</div>';

                            // Inject after random paragraph
                            injectionPoint.after(htmlToInject);
                        }
                    }
                });
            }
        }
    }
});
