// Removed redundant script
document.addEventListener('DOMContentLoaded', function() {
  // Set the column count threshold. Tables with MORE columns than this will get a scrollbar.
  // A threshold of 2 means any table with 3 or more columns will become scrollable.
  const columnThreshold = 2;

  document.querySelectorAll('.post-body table').forEach(table => {
    if (table.closest('.dj-table-container')) return; // Skip if already wrapped

    const firstRow = table.querySelector('thead tr, tbody tr');
    if (firstRow) {
      const columnCount = firstRow.children.length;

      if (columnCount > columnThreshold) {
        const wrapper = document.createElement('div');
        wrapper.className = 'dj-table-container';
        table.parentNode.insertBefore(wrapper, table);
        wrapper.appendChild(table);
      }
    }
  });
});
