document.addEventListener("DOMContentLoaded", function() {
    // --- Floating WhatsApp Button Logic ---
    const whatsappBtn = document.querySelector('.floating-whatsapp-btn');
    const alertBox = document.querySelector('.whatsapp-alert-box');

    // Check if the user has visited before using localStorage
    if (!localStorage.getItem('whatsappAlertShown')) {
        // If it's the first visit, show the alert after a 2-second delay
        setTimeout(function() {
            if (alertBox) {
                alertBox.classList.add('show-alert');
            }
        }, 2000);
    }

    if (whatsappBtn) {
        whatsappBtn.addEventListener('click', function() {
            // When the button is clicked, hide the alert and set a flag in localStorage
            // so it doesn't show again on the next visit.
            if (alertBox) {
                alertBox.classList.remove('show-alert');
            }
            localStorage.setItem('whatsappAlertShown', 'true');
        });
    }

    // Optional: Automatically hide the alert after 12 seconds if the user doesn't click
    setTimeout(function() {
        if (alertBox && alertBox.classList.contains('show-alert')) {
            alertBox.classList.remove('show-alert');
        }
    }, 12000); // Alert is visible for 10 seconds (2s delay + 10s visibility)
});
