document.addEventListener('DOMContentLoaded', function() {
    const marquees = document.querySelectorAll('.featured-post-pro .widget .widget-content marquee');

    marquees.forEach(function(marquee) {
        const content = marquee.innerHTML;

        const container = document.createElement('div');
        container.className = 'marquee-container';

        const contentWrapper = document.createElement('div');
        contentWrapper.className = 'marquee-content';
        // Only duplicate once (not twice)
        contentWrapper.innerHTML = content;

        container.appendChild(contentWrapper);
        marquee.parentNode.replaceChild(container, marquee);
    });
});
