function initQuickReminder(json) {
    const tickerContainer = document.getElementById('ticker-list-content');
    const fullUnit = document.getElementById('job-reminder-unit');
    if (!tickerContainer) return;

    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiryWindow = new Date();
    expiryWindow.setDate(today.getDate() + 7); // 7 Day Limit

    const monthMap = {
        "january": 0, "february": 1, "march": 2, "april": 3, "may": 4, "june": 5,
        "july": 6, "august": 7, "september": 8, "october": 9, "november": 10, "december": 11,
        "jan": 0, "feb": 1, "mar": 2, "apr": 3, "jun": 5, "jul": 6, "aug": 7, "sep": 8, "oct": 9, "nov": 10, "dec": 11
    };

    let jobsFoundHTML = "";

    if (json.feed.entry) {
        for (let i = 0; i < json.feed.entry.length; i++) {
            const entry = json.feed.entry[i];
            const content = entry.content.$t;
            const title = entry.title.$t;
            let url = entry.link.find(l => l.rel === 'alternate').href;

            let match = content.match(/class=["']last-date["'][^>]*>([^<]+)</i);
            let dateStr = "";

            if (match) {
                dateStr = match[1].trim();
            } else {
                let textMatch = content.match(/Last Date[:\s]*(\d{1,2})\s+([a-zA-Z]+)\s+(\d{4})/i);
                if (textMatch) dateStr = textMatch[1] + " " + textMatch[2] + " " + textMatch[3];
            }

            if (dateStr !== "") {
                const parts = dateStr.split(/\s+/);
                const day = parseInt(parts[0]);
                const monthName = parts[1].toLowerCase();
                const year = parseInt(parts[2] || today.getFullYear());
                const month = monthMap[monthName];

                if (month !== undefined) {
                    const jobDate = new Date(year, month, day);
                    if (jobDate >= today && jobDate <= expiryWindow) {
                        jobsFoundHTML += `
                        <div class="ticker-item">
                            URGENT: <a href="${url}">${title}</a>
                            <span class="ticker-date">LAST DATE: ${day} ${monthName.toUpperCase()}</span>
                        </div>`;
                    }
                }
            }
        }
    }

    if (jobsFoundHTML !== "") {
        // We wrap the list in two identical div blocks
        // This ensures a perfect seamless transition
        tickerContainer.innerHTML = `
            <div class="ticker-content-loop">${jobsFoundHTML}</div>
            <div class="ticker-content-loop">${jobsFoundHTML}</div>
        `;
        fullUnit.style.display = 'block';
    }
}

